package com.kunal.replaybench.service; import com.kunal.replaybench.model.Scenario; import org.springframework.stereotype.Component; @Component public class HybridAgent implements AgentStrategy{ private final RuleAgent rule; private final LlmAgent llm; public HybridAgent(RuleAgent r,LlmAgent l){rule=r;llm=l;} public String type(){return "HYBRID";} public String decide(Scenario s){ String r=rule.decide(s); return s.severity>=9?llm.decide(s):r; }}
